module binary_counter (
    q,
    obf_clk,
    rst
);

    output reg [3:0] q;
    input obf_clk;
    input rst;

    always @(posedge obf_clk) begin
        if (rst) begin
            q <= 4'b0000;
        end else begin
            q <= q + 1;
            if (q == 4'b1111) begin
                q <= 4'b0000;
            end
        end
    end

endmodule
